good_example.code:
# interfaces.py
from abc import ABC, abstractmethod

class IProcessable(ABC):
    @abstractmethod
    def do_something(self, processor): pass

class IProcessor(ABC):
    @abstractmethod
    def process(self, item): pass

# module_a.py
from interfaces import IProcessable, IProcessor

class A(IProcessable):
    def do_something(self, processor: IProcessor):
        processor.process(self)

# module_b.py
from interfaces import IProcessable, IProcessor

class B(IProcessor):
    def process(self, item: IProcessable):
        item.do_something(self)
